const webhookData = $('Client Intake Form').first().json.body;

// Generate Client ID
const timestamp = Date.now();
const randomNum = Math.floor(Math.random() * 10000);
const clientNumber = String((timestamp % 10000) + randomNum).padStart(4, "0");

return [{
  json: {
    clientId: `CLIENT-${clientNumber}`,

    // Fixed field mappings (snake_case from webhook)
    companyName: webhookData.company_name || "",
    contactName: webhookData.contact_name || "",
    email: webhookData.email || "",
    phone: webhookData.phone || "",
    industry: webhookData.industry || "",
   budget: Number(webhookData.budget_usd || 0),
    requestedService: webhookData.requested_service || "",
    projectDescription: webhookData.project_description || "",

    // Optional fields
    priority: webhookData.priority || "",
    riskLevel: webhookData.risk_level || "",

    status: "New"
  }
}];

const timestamp = Date.now();
const randomNum = Math.floor(Math.random() * 10000);

const projectNumber = String(
  (timestamp % 10000) + randomNum
).padStart(4, "0");

return [{
  json: {
    ...$input.first().json,
    projectId: `PROJ-${projectNumber}`
  }
}];

const budget = Number($json.fields["Budget (USD)"] || 0);

let complexity = "";
let requiredLevel = "";
let riskLevel = "";
let priority = "";

if (budget < 25000) {
  complexity = "Low";
  requiredLevel = "Junior";
  riskLevel = "Low";
  priority = "Low";
} 
else if (budget < 75000) {
  complexity = "Medium";
  requiredLevel = "Engineer";
  riskLevel = "Medium";
  priority = "High";
} 
else {
  complexity = "High";
  requiredLevel = "Senior";
  riskLevel = "High";
  priority = "Critical";
}

return [
  {
    json: {
      ...$json,
      budget,
      complexity,
      requiredLevel,
      riskLevel,
      priority
    }
  }
];

